head.script:
scwin.initData = {
	"observeEvent" : false,
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 4,
	}
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL3100000", {"initScreenCallback" : scwin.searchDatas});
	// ecsLib.setChartResizeObserver(this);
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("endDtM", utilLib.getCurrentDate("yyyyMM"));
	//dmaSearchParam.set("strtDtM", utilLib.addMonth(dmaSearchParam.get("endDtM"), -1));
	dmaSearchParam.set("strtDtM", dmaSearchParam.get("endDtM"));
	dmaSearchParam.set("endDtY", utilLib.getCurrentDate("yyyy"));
	//dmaSearchParam.set("strtDtY", String(Number(dmaSearchParam.get("endDtY")) - 1));
	dmaSearchParam.set("strtDtY", dmaSearchParam.get("endDtY"));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("deptCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	dmaSearchParam.set("lastBasinCd", ecsBasinDivCd);

	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = strtDate

		if (String(strtDate).length != 6) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	} else if (cnd == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = strtDate

		if (String(strtDate).length != 4) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	}
	cnd = cnd == "M" ? "mnby" : "yyby";

	scwin.queryString = `?strtDt=${strtDate}`;
	scwin.queryString += `&endDt=${endDate}`;
	scwin.queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	scwin.queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	scwin.queryString += `&cnd=${cnd}`;

	var option = {
		action : "cl/cnstscexcclc/retrieve-cnstsc-excclc.do" +
			scwin.queryString,
		method : "get",
		resData : dltItslfCnstnExcclcSttus,
		success : "scwin.inqireItslfCnstnExcclcSttusChart",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);

	scwin.inqireCsmtCnstnExcclcSttus();
};

/**
 * 조회조건에 맞게 차트 데이터를 조회한다.
 * @param
 * @return
 */
scwin.inqireItslfCnstnExcclcSttusChart = function() {
	var option = {
		action : "cl/cnstscexcclc/retrieve-cnstsc-excclc-chart.do" +
			scwin.queryString,
		method : "get",
		resData : dltChartList,
		success : "scwin.inqireItslfCnstnExcclcSttusChartCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireItslfCnstnExcclcSttusChartCallback = function() {
	spnGridTotal.setValue(dltItslfCnstnExcclcSttus.getRowCount());

	// 자체 소비정산 현황 차트 생성
	scwin.setChartItslfCnstnExcclcSttus();
};

/**
 * 조회조건에 맞게 위탁사업장 data를 조회한다.
 * @param
 * @return
 */
scwin.inqireCsmtCnstnExcclcSttus = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = strtDate

		if (String(strtDate).length != 6) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	} else if (cnd == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = strtDate

		if (String(strtDate).length != 4) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	}
	cnd = cnd == "M" ? "mnby" : "yyby";

	scwin.queryString = `?strtDt=${strtDate}`;
	scwin.queryString += `&endDt=${endDate}`;
	scwin.queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	scwin.queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	scwin.queryString += `&cnd=${cnd}`;

	var option = {
		action : "cl/cnstscexcclc/retrieve-cnstsc-excclc-csmt-bplc.do" +
			scwin.queryString,
		method : "get",
		resData : dltCsmtCnstnExcclcSttus,
		success : "scwin.inqireCsmtCnstnExcclcSttusCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 위탁사업장 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCsmtCnstnExcclcSttusCallback = function() {
	spnGridTotal2.setValue(dltCsmtCnstnExcclcSttus.getRowCount());

	// 위탁 소비정산 현황 차트 생성
	scwin.setChartCsmtCnstnExcclcSttus();
};

/**
 * 조회조건 재조회
 * @param info
 * @return
 */
scwin.inqireCnsmpSttusCnd = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = dmaSearchParam.get("endDtM");
	} else if (cnd == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = dmaSearchParam.get("endDtY");
	}
	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;

	var option = {
		action : "cn/cnsmpsttus/retrieve-cnsmp-sttus-cnd.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.dmaSearchParam_onmodelchange = function(info) {
	if ((info.key.startsWith("strtDt") || info.key.startsWith("endDt")) && info.oldValue) {
		var newYear = String(info.newValue).substr(0, 4);
		var oldYear = String(info.oldValue).substr(0, 4);
		if (newYear != oldYear) {
			scwin.inqireCnsmpSttusCnd();
		}
	}
};

/**
 * 라디오버튼 선택에 따라 조회연도를 변경한다.
 * @param
 * @return
 */
scwin.radYmBy_onviewchange = function() {
	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		grpCalMNm.setStyle("display", "");
		grpCalMBox.setStyle("display", "");
		grpCalYNm.setStyle("display", "none");
		grpCalYBox.setStyle("display", "none");
	} else if (cnd == "Y") {
		grpCalYNm.setStyle("display", "");
		grpCalYBox.setStyle("display", "");
		grpCalMNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
	} else {
		return;
	}
};

scwin.acbBasin_onviewchange = function(info) {
	dmaSearchParam.set("basinCd", info.newValue);
	scwin.inqireCnsmpSttusCnd();
};

scwin.acbDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 자체 소비정산 현황 차트 생성
 */
scwin.setChartItslfCnstnExcclcSttus = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerItslfCnstnExcclcSttus";
	rMateChartH5.create($p.id + "ChartItslfCnstnExcclcSttus", grpChartItslfCnstnExcclcSttus.getID(), chartVars, "100%", "100%");
};

/**
* 자체 소비정산 현황 차트 설정
*/
scwin.chartReadyHandlerItslfCnstnExcclcSttus = function(id) {
	var cnstscChartsData = dltChartList.getAllJSON();
	var nameList = dltAutoCondition1.getAllJSON();
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	if (ecsBasinDivCd == "ALL" && ecsChrgDeptId == "ALL") {
		/*
		var name = nameList.map(obj => obj.cmmnCdNm);
		name.forEach(prefix => {
			cnstscChartsData.forEach(obj => obj["nm"] = prefix);
		});
		*/
		 cnstscChartsData.forEach(obj => obj["nm"] = obj.nm.slice(0, -4));
	}

	var maxData = cnstscChartsData.reduce((max, obj) => Math.max(max, obj.usgqty), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var amtMaxData = cnstscChartsData.reduce((max, obj) => Math.max(max, obj.amt), 0);
	var amtChartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(amtMaxData.toFixed(0)).length - 2));
	var amtInterval = Math.ceil((amtMaxData / scwin.initData.chart.chartIntervalCount) / amtChartUnit) * amtChartUnit;
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+ '		<Legend defaultMouseOverAction="false" />'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="nm" padding="0.7"/>'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="사용량(kWh)"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries color="#666666" yField="usgqty" displayName="사용량(kWh)">'
		+'						<fill>'
		+'							<SolidColor color="' + solidColor + '"/>'
		+'						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="amt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="금액(원)">' // labelPosition="up"
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxis2" interval="' + amtInterval + '" formatter="{numFmt}" title="금액(원)"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate/>'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+'		<horizontalAxisRenderers>'
		+'			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+'		</horizontalAxisRenderers>'
		+ '	</Combination2DChart>'
		+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(cnstscChartsData);
};

/**
 * 위탁 소비정산 현황 차트 생성
 */
scwin.setChartCsmtCnstnExcclcSttus = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCsmtCnstnExcclcSttus";
	rMateChartH5.create($p.id + "ChartCsmtCnstnExcclcSttus", grpChartCsmtCnstnExcclcSttus.getID(), chartVars, "100%", "100%");
};

/**
 * 위탁 소비정산 현황 차트설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerCsmtCnstnExcclcSttus = function(id) {
	var cnstscChartsData = dltCsmtCnstnExcclcSttus.getAllJSON();
	var chartData = [];

	var nmObj = {
		"취수시설" : "01",
		"가압시설" : "02",
		"정수시설" : "03",
		"건물" : "04",
		"수송" : "05",
		"댐시설" : "06",
		"기타" : "99"
	};

	Object.keys(nmObj).forEach(key => {
		var usgqtySum = 0;
		var amtSum = 0;
		cnstscChartsData.forEach(obj => {
			if (obj.dscfcProcsTyCd == nmObj[key]) {
				usgqtySum += Number(obj.usgqty);
				amtSum += Number(obj.amt);
			}
		}, 0);
		chartData.push({
			"nm" : key,
			"usgqty" : usgqtySum,
			"amt" : amtSum
		});
	});

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.usgqty), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var amtMaxData = chartData.reduce((max, obj) => Math.max(max, obj.amt), 0);
	var amtChartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(amtMaxData.toFixed(0)).length - 2));
	var amtInterval = Math.ceil((amtMaxData / scwin.initData.chart.chartIntervalCount) / amtChartUnit) * amtChartUnit;
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+ '		<Legend defaultMouseOverAction="false" />'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="nm" padding="0.7"/>'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="사용량(kWh)"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries color="#666666" yField="usgqty" displayName="사용량(kWh)">'
		+'						<fill>'
		+'							<SolidColor color="' + solidColor + '"/>'
		+'						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="amt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="금액(원)">' // labelPosition="up"
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxis2" interval="' + amtInterval + '" formatter="{numFmt}" title="금액(원)"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate/>'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	</Combination2DChart>'
		+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 1);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 자체 소비정산 현황 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnGridTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		useDataFormat: true,
		applyDataFormat : true,
		rowHeight : 40,
		useStyle: true,
		hidden: 1
	}
	grdItslfCnstnExcclcSttus.advancedExcelDownload(options, infoArr);
};

/**
 * 위탁 소비정산 현황 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel2_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnGridTitle2.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		useDataFormat: true,
		applyDataFormat : true,
		rowHeight : 40,
		useStyle: true,
		hidden: 1
	}
	grdCsmtCnstnExcclcSttu.advancedExcelDownload(options, infoArr);
};
